import{_ as l,c as r,o,a5 as a,j as e}from"./chunks/framework.Dtwt352Q.js";const u=JSON.parse('{"title":"v1.1.49：修复会话卡死、新增 Haskell 格式化","description":"","frontmatter":{},"headers":[],"relativePath":"changelog/v1.1.49.md","filePath":"changelog/v1.1.49.md","lastUpdated":1772014034000}'),t={name:"changelog/v1.1.49.md"};function n(s,i,d,h,p,c){return o(),r("div",null,[...i[0]||(i[0]=[a('<h1 id="v1-1-49-修复会话卡死、新增-haskell-格式化" tabindex="-1">v1.1.49：修复会话卡死、新增 Haskell 格式化 <a class="header-anchor" href="#v1-1-49-修复会话卡死、新增-haskell-格式化" aria-label="Permalink to “v1.1.49：修复会话卡死、新增 Haskell 格式化”">​</a></h1><p><strong>发布日期</strong>：2026年02月03日</p><hr><h2 id="一句话总结" tabindex="-1">一句话总结 <a class="header-anchor" href="#一句话总结" aria-label="Permalink to “一句话总结”">​</a></h2><p>这次更新修复了多个关键问题，包括会话卡死、文件状态计算错误等，新增 Haskell 代码格式化支持，并大幅改进桌面端交互体验。</p><hr><h2 id="问题修复-会话卡死问题" tabindex="-1">问题修复：会话卡死问题 <a class="header-anchor" href="#问题修复-会话卡死问题" aria-label="Permalink to “问题修复：会话卡死问题”">​</a></h2><h3 id="之前的问题" tabindex="-1">之前的问题 <a class="header-anchor" href="#之前的问题" aria-label="Permalink to “之前的问题”">​</a></h3><p>当会话遇到错误后，状态卡在错误中，导致无法开始新会话。</p><h3 id="现在的情况" tabindex="-1">现在的情况 <a class="header-anchor" href="#现在的情况" aria-label="Permalink to “现在的情况”">​</a></h3><p>修复了会话状态管理，错误后可以正常开始新会话，OpenCode 不再卡死。</p><hr><h2 id="新功能-haskell-代码格式化" tabindex="-1">新功能：Haskell 代码格式化 <a class="header-anchor" href="#新功能-haskell-代码格式化" aria-label="Permalink to “新功能：Haskell 代码格式化”">​</a></h2><h3 id="这次更新了什么" tabindex="-1">这次更新了什么？ <a class="header-anchor" href="#这次更新了什么" aria-label="Permalink to “这次更新了什么？”">​</a></h3><p>新增 Ormolu 代码格式化器支持，可以格式化 Haskell 代码。</p><h3 id="什么是-ormolu" tabindex="-1">什么是 Ormolu？ <a class="header-anchor" href="#什么是-ormolu" aria-label="Permalink to “什么是 Ormolu？”">​</a></h3><p>Ormolu 是 Haskell 的代码格式化工具，类似于 JavaScript 的 Prettier，可以自动统一代码风格。</p><h3 id="如何使用" tabindex="-1">如何使用？ <a class="header-anchor" href="#如何使用" aria-label="Permalink to “如何使用？”">​</a></h3><p>在项目中包含 Haskell 代码时，OpenCode 会自动使用 Ormolu 进行格式化。</p><hr><h2 id="新功能-自定义-mdns-域名" tabindex="-1">新功能：自定义 mDNS 域名 <a class="header-anchor" href="#新功能-自定义-mdns-域名" aria-label="Permalink to “新功能：自定义 mDNS 域名”">​</a></h2><h3 id="这次更新了什么-1" tabindex="-1">这次更新了什么？ <a class="header-anchor" href="#这次更新了什么-1" aria-label="Permalink to “这次更新了什么？”">​</a></h3><p>添加了 <code>--mdns-domain</code> 标志，可以自定义 mDNS 主机名。</p><h3 id="有什么用" tabindex="-1">有什么用？ <a class="header-anchor" href="#有什么用" aria-label="Permalink to “有什么用？”">​</a></h3><p>在局域网访问时，可以自定义更友好的域名。</p><h3 id="如何使用-1" tabindex="-1">如何使用？ <a class="header-anchor" href="#如何使用-1" aria-label="Permalink to “如何使用？”">​</a></h3>',26),e("div",{class:"language-bash"},[e("button",{title:"Copy Code",class:"copy"}),e("span",{class:"lang"},"bash"),e("pre",null,[e("code",{"v-pre":""},"opencode --mdns-domain mydevice.local")])],-1),a('<hr><h2 id="改进-桌面端交互体验" tabindex="-1">改进：桌面端交互体验 <a class="header-anchor" href="#改进-桌面端交互体验" aria-label="Permalink to “改进：桌面端交互体验”">​</a></h2><h3 id="项目搜索" tabindex="-1">项目搜索 <a class="header-anchor" href="#项目搜索" aria-label="Permalink to “项目搜索”">​</a></h3><p>现在可以在桌面端搜索项目，快速找到要打开的项目。</p><h3 id="会话导航" tabindex="-1">会话导航 <a class="header-anchor" href="#会话导航" aria-label="Permalink to “会话导航”">​</a></h3><p>新增键盘快捷键在未读会话之间切换。</p><h3 id="tab-关闭快捷键" tabindex="-1">Tab 关闭快捷键 <a class="header-anchor" href="#tab-关闭快捷键" aria-label="Permalink to “Tab 关闭快捷键”">​</a></h3><p>添加了关闭标签页的快捷键。</p><h3 id="响应式设计" tabindex="-1">响应式设计 <a class="header-anchor" href="#响应式设计" aria-label="Permalink to “响应式设计”">​</a></h3><p>新增断点，优化大屏幕布局。</p><hr><h2 id="问题修复" tabindex="-1">问题修复 <a class="header-anchor" href="#问题修复" aria-label="Permalink to “问题修复”">​</a></h2><h3 id="文件状态计算" tabindex="-1">文件状态计算 <a class="header-anchor" href="#文件状态计算" aria-label="Permalink to “文件状态计算”">​</a></h3><p>新增和删除的文件现在能正确计算状态。</p><h3 id="openai-会话标题生成" tabindex="-1">OpenAI 会话标题生成 <a class="header-anchor" href="#openai-会话标题生成" aria-label="Permalink to “OpenAI 会话标题生成”">​</a></h3><p>修复了使用 OpenAI 模型时标题生成的问题。</p><h3 id="任务状态显示" tabindex="-1">任务状态显示 <a class="header-anchor" href="#任务状态显示" aria-label="Permalink to “任务状态显示”">​</a></h3><p>修复了任务状态无法显示当前工具状态的问题。</p><h3 id="copilot-provider" tabindex="-1">Copilot Provider <a class="header-anchor" href="#copilot-provider" aria-label="Permalink to “Copilot Provider”">​</a></h3><p>修复了 Copilot provider 的系统消息内容转换问题。</p><h3 id="agent-变量作用域" tabindex="-1">Agent 变量作用域 <a class="header-anchor" href="#agent-变量作用域" aria-label="Permalink to “Agent 变量作用域”">​</a></h3><p>修复了 agent variant 未正确作用域到 model 的问题。</p><h3 id="提及隐藏文件" tabindex="-1">@ 提及隐藏文件 <a class="header-anchor" href="#提及隐藏文件" aria-label="Permalink to “@ 提及隐藏文件”">​</a></h3><p>修复了以 <code>.</code> 开头的文件夹和文件无法用 @ 提及的问题。</p><h3 id="windows-pty-编码" tabindex="-1">Windows PTY 编码 <a class="header-anchor" href="#windows-pty-编码" aria-label="Permalink to “Windows PTY 编码”">​</a></h3><p>为 Windows PTY 添加 UTF-8 编码默认值。</p><hr><h2 id="要不要升级" tabindex="-1">要不要升级？ <a class="header-anchor" href="#要不要升级" aria-label="Permalink to “要不要升级？”">​</a></h2><table tabindex="0"><thead><tr><th>情况</th><th>建议</th></tr></thead><tbody><tr><td>遇到会话卡死问题</td><td>✅ 强烈推荐</td></tr><tr><td>使用 Haskell</td><td>✅ 推荐升级</td></tr><tr><td>桌面端用户</td><td>✅ 推荐升级</td></tr><tr><td>用得好好的</td><td>可以等下次</td></tr></tbody></table><p><strong>升级命令</strong>：</p>',30),e("div",{class:"language-bash"},[e("button",{title:"Copy Code",class:"copy"}),e("span",{class:"lang"},"bash"),e("pre",null,[e("code",{"v-pre":""},"opencode upgrade")])],-1),a('<hr><h2 id="技术细节-可跳过" tabindex="-1">技术细节（可跳过） <a class="header-anchor" href="#技术细节-可跳过" aria-label="Permalink to “技术细节（可跳过）”">​</a></h2><details><summary>点击展开完整更新列表</summary><h3 id="core" tabindex="-1">Core <a class="header-anchor" href="#core" aria-label="Permalink to “Core”">​</a></h3><ul><li>Revert pull request that was mistakenly merged</li><li>Add --mdns-domain flag to customize mDNS hostname (@luiz290788)</li><li>Added and deleted file status now correctly calculated in app</li><li>Add User-Agent header for GitLab AI Gateway requests (@vglafirov)</li><li>Add Ormolu code formatter for Haskell (@mimi1vx)</li><li>Use OpenTUI OSC52 clipboard implementation</li><li>Convert system message content to string for Copilot provider (@jogi47)</li><li>Give OPENCODE_CONFIG_CONTENT proper priority for setting config based on docs (@OpeOginni)</li><li>Fixed session title generation with OpenAI models (@oomathias)</li><li>Simplify directory tree output for prompts</li><li>Fix task status to show current tool state from message store</li><li>Allow starting new sessions after errors by fixing stuck session status</li><li>Adjust resolve parts to properly order tool calls when messages contain multiple @ references</li><li>Hide badge for builtin slash commands</li><li>Add workspace tests to the app (@neriousy)</li><li>Send custom agent prompts as developer messages instead of user messages when using Codex subscriptions</li><li>Fixed variant logic for Anthropic models through OpenAI compatibility endpoint</li><li>Add prompt caching support for Claude Opus on AWS Bedrock (@rgodha24)</li><li>Scope agent variant to model (@neavo)</li><li>Prevent duplicate AGENTS.md injection when reading instruction files (@code-yeongyu)</li><li>OpenCode no longer hangs when using client.app.log() during initialization (@desmondsow)</li><li>Remove outer backtick wrapper in session transcript tool formatting (@zerone0x)</li><li>Allow user plugins to override built-in auth plugins (@JosXa)</li><li>Binary file handling in file view (@alexyaroshuk)</li><li>Ensure switching Anthropic models mid-conversation works without errors and fix reasoning opaque not being picked up for Gemini models</li><li>Fix issue where folders and files starting with &quot;.&quot; could not be mentioned with @</li><li>Show actual retry error message instead of generic error message</li><li>Use process.env directly for runtime environment mutations in provider (@jerome-benoit)</li><li>Add reasoning variants support for SAP AI Core (@jerome-benoit)</li><li>Add UTF-8 encoding defaults for Windows PTY (@01luyicheng)</li></ul><h3 id="tui" tabindex="-1">TUI <a class="header-anchor" href="#tui" aria-label="Permalink to “TUI”">​</a></h3><ul><li>Respect terminal transparency in system theme (@pablopunk)</li><li>Truncate session title in exit banner to prevent display overflow</li><li>Show exit message banner in TUI</li><li>Add spinner animation for Task tool</li><li>Correct pluralization of match count in grep and glob tools (@adamjhf)</li><li>Remove extra padding between search and results in dialog-select</li><li>Add UI for skill tool in session view</li><li>Conditionally render bash tool output in TUI</li><li>Add skill dialog for selecting and inserting skills</li><li>Enable password authentication for remote session attachment</li><li>Fix documentation issues (@lailoo)</li><li>Revert skill slash commands feature</li><li>Add skill slash commands to the app</li></ul><h3 id="desktop" tabindex="-1">Desktop <a class="header-anchor" href="#desktop" aria-label="Permalink to “Desktop”">​</a></h3><ul><li>Fix prompt input overflow issue in app (@neriousy)</li><li>Sidebar losing projects on collapse has been fixed</li><li>Add workspace toggle command to command palette and prompt input (@alexyaroshuk)</li><li>Search through sessions</li><li>Standardize icon sizes in the application</li><li>Navigate to last project on open</li><li>User messages not rendering consistently</li><li>Add project context menu on right-click</li><li>Open project search in app (@neriousy)</li><li>Add tab close keybind to app (@ProdigyRahul)</li><li>Enhance responsive design with additional breakpoints for larger screen layout adjustments (@OpeOginni)</li><li>Add keyboard shortcuts for navigating between unread sessions (@Brendonovich)</li><li>Fix Rust build and bindings formatting in desktop application (@Brendonovich)</li><li>Remove unnecessary setTimeout in desktop app (@Brendonovich)</li><li>Throttle window state persistence in desktop application (@Brendonovich)</li><li>Integrate tauri-specta for desktop application (@Brendonovich)</li><li>Keep macOS titlebar stable under zoom (@Brendonovich)</li><li>Kill zombie server process on startup timeout (@heyitsmohdd)</li><li>Show skill and MCP badges for slash commands</li><li>Use static language names in Thai localization (@alexyaroshuk)</li><li>Add tests for general settings, shortcuts, providers and status popover (@neriousy)</li><li>Fixed session header &#39;share&#39; button to hug content (@alexyaroshuk)</li></ul></details><hr><p><a href="./">← 返回更新日志</a></p>',5)])])}const b=l(t,[["render",n]]);export{u as __pageData,b as default};
